#!/bin/bash
set -e
PAYLOAD=''
TARGET_DIR="$HOME/trend-crawler"
if [ ! -d "$TARGET_DIR" ]; then echo "Error: $TARGET_DIR が見つかりません"; exit 1; fi
echo "$PAYLOAD" | base64 -d | tar -xzf - -C "$TARGET_DIR"
echo "✅ ファイルを更新しました"
cd "$TARGET_DIR"
git add topics.yaml agents/summarize_agent.py agents/export_agent.py main.py
git commit -m "feat: summarize改良-tool型総括・trend型世界潮流・AI topic拡張"
git push origin main
echo "✅ GitHub にプッシュ完了"
